3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export const nextGeneration = (cells: Cell[]): Cell[] => {
15	  const aliveKeys = new Set(cells.map(keyOf));
16	  const isAlive = (cell: Cell): boolean => aliveKeys.has(keyOf(cell));
17	
18	  const countLiveNeighbors = (cell: Cell): number =>
19	    neighborsOf(cell).filter(isAlive).length;
20	
21	  const livesNextGeneration = (cell: Cell): boolean => {
22	    const liveNeighbors = countLiveNeighbors(cell);
23	    return liveNeighbors === 3 || (liveNeighbors === 2 && isAlive(cell));
24	  };
25	
26	  const candidates = cells.flatMap((cell) => [cell, ...neighborsOf(cell)]);
27	  const uniqueCandidates = new Map(candidates.map((cell) => [keyOf(cell), cell]));
28	
29	  return [...uniqueCandidates.values()].filter(livesNextGeneration);
30	};
