1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single isolated live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a 2x2 block unchanged (still life)", () => {
15	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(input);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(input));
19	  });
20	  it("transforms a vertical blinker into a horizontal blinker", () => {
21	    const input: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(input);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(expected));
26	  });
27	  it("creates a new live cell when a dead cell has exactly 3 live neighbors (reproduction)", () => {
28	    const input: [number, number][] = [[0, 2], [1, 2], [0, 1]];
29	    const expected: [number, number][] = [[0, 2], [1, 2], [0, 1], [1, 1]];
30	    const result = nextGeneration(input);
31	    expect(result).toHaveLength(4);
32	    expect(result).toEqual(expect.arrayContaining(expected));
33	  });
34	  it("kills a live cell with more than 3 live neighbors (overpopulation)", () => {
35	    const input: [number, number][] = [
36	      [0, 0], [1, 0], [2, 0],
37	      [1, 1],
38	      [0, 2], [1, 2], [2, 2],
39	    ];
40	    const result = nextGeneration(input);
41	    // Center (1,1) has 6 live neighbors and dies (overpopulation).
42	    const centerSurvives = result.some(([x, y]) => x === 1 && y === 1);
43	    expect(centerSurvives).toBe(false);
44	  });
